-- ============================================
-- Fluxo 5B inventário completo (Lei + Lei Complementar) - Romeu Zema / MG / Governador
-- ============================================
-- Não aplicar ao Supabase remoto sem autorização explícita.
-- Fonte oficial: Assembleia Legislativa de Minas Gerais - Legislação Mineira
-- Universo: 2548 atos do Executivo (2.526 LEI + 22 LCP) sancionados ou promulgados
--   pelo mandato Governador/MG de Romeu Zema entre 2019-01-09 e 2026-04-29.
-- Range enumerado: LEI 23.290..25.839, LCP 80..200.
-- Cutoff explícito: 2026-04-29 (Lei 25.839 - última lei real publicada antes da extração).
-- Coverage_id: romeu-zema-mg-inventario-completo-leis-ordinarias-complementares-2019-2026-04-30
-- Curation_batch_id: romeu-zema-mg-inventario-completo-20260430
-- Artefato: fonte interna de curadoria
--
-- Contrato schema corrigido (v4):
--   autoridade_papel ∈ {titular, vice_interino, mesa_legislativa, outro, nao_informado}
--   tipo_relacao ∈ {lei_sancionada, lei_promulgada_pelo_legislativo}
--   100% das rows com tipo_relacao=lei_promulgada_pelo_legislativo tem autoridade_papel=mesa_legislativa
--   Vice-Governador em exercício classificado como vice_interino (NÃO titular)
--   Presidente ALMG/TJMG em exercício classificado como outro (NÃO titular)
--
-- Esta migration:
--   1) Insere as 2538 normas faltantes (com NOT EXISTS guard contra as 10 já presentes).
--   2) UPDATE pre-promocao das 10 rows preexistentes (lote A+B 24.304..24.470/2023)
--      acrescentando coverage_id alvo e coverage_scope=inventario_completo.
--   3) Não toca projetos_lei.
-- ============================================

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM candidatos c WHERE c.slug = 'romeu-zema'
  ) THEN
    RAISE EXCEPTION 'romeu-zema nao encontrado em candidatos';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM candidatos c
    JOIN historico_politico hp ON hp.candidato_id = c.id
    WHERE c.slug = 'romeu-zema'
      AND hp.tipo_evento = 'mandato'
      AND hp.estado = 'MG'
      AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
      AND hp.periodo_inicio <= 2019
  ) THEN
    RAISE EXCEPTION 'mandato Governador/MG de romeu-zema (>=2019) nao encontrado';
  END IF;
END $$;

-- ============================================
-- PRE-PROMOCAO: garantir que as 10 rows existentes (lote A+B 2023) recebam coverage_id
-- ============================================
UPDATE legislacao_mandato_executivo lme
SET metadata = jsonb_set(
  jsonb_set(
    COALESCE(lme.metadata, '{}'::jsonb),
    '{coverage_id}',
    to_jsonb('romeu-zema-mg-inventario-completo-leis-ordinarias-complementares-2019-2026-04-30'::text),
    true
  ),
  '{coverage_scope}',
  to_jsonb('inventario_completo'::text),
  true
)
FROM candidatos c
WHERE lme.candidato_id = c.id
  AND c.slug = 'romeu-zema'
  AND lme.metadata ->> 'coverage_scope' IN (
    'inventario_ampliado_parcial_mg_lote_a_20260429',
    'inventario_ampliado_parcial_mg_lote_b_20260429'
  )
  AND (lme.metadata ->> 'coverage_id' IS DISTINCT FROM 'romeu-zema-mg-inventario-completo-leis-ordinarias-complementares-2019-2026-04-30');

