  esfera,
  uf_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
);

WITH target AS (
  SELECT
    c.id AS candidato_id,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND hp.tipo_evento = 'mandato'
        AND hp.estado = 'MG'
        AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
        AND hp.periodo_inicio <= 2019
      ORDER BY hp.periodo_inicio DESC
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  WHERE c.slug = 'romeu-zema'
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  seed.tipo_relacao,
  seed.esfera,
  seed.uf_norma,
  seed.tipo_norma,
  seed.numero,
  seed.ano,
  seed.data_norma::date,
  seed.ementa,
  seed.signatario,
  seed.autoridade_papel,
  seed.fonte_primaria_url,
  seed.fonte_primaria_titulo,
  seed.fonte_tramitacao_url,
  seed.identificador_fonte,
  seed.metadata::jsonb
FROM target
CROSS JOIN _seed_romeu_zema_mg_completo_legislacao seed
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.tipo_relacao = seed.tipo_relacao
      AND lme.tipo_norma = seed.tipo_norma
      AND lme.numero = seed.numero
      AND lme.ano = seed.ano
      AND lme.fonte_primaria_url = seed.fonte_primaria_url
  );

-- ============================================
-- POST-VALIDACAO (counts reais apos correcao v4)
-- ============================================
DO $$
DECLARE
  v_candidato_id UUID;
  v_post_total INT;
  v_post_with_target_id INT;
  v_post_titular INT;
  v_post_vice_interino INT;
  v_post_mesa_legislativa INT;
  v_post_outro INT;
  v_post_nao_informado INT;
  v_post_sancionada INT;
  v_post_promulgada INT;
  v_invalid_aut INT;
  v_es_almeida INT;
  v_promulgada_wrong_aut INT;
  v_empty_url INT;
BEGIN
  SELECT id INTO v_candidato_id FROM candidatos WHERE slug = 'romeu-zema';

  SELECT COUNT(*) INTO v_post_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id;

  SELECT COUNT(*) INTO v_post_with_target_id
  FROM legislacao_mandato_executivo lme
  WHERE lme.candidato_id = v_candidato_id
    AND lme.metadata ->> 'coverage_id' = 'romeu-zema-mg-inventario-completo-leis-ordinarias-complementares-2019-2026-04-30';

  SELECT COUNT(*) INTO v_post_titular FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND autoridade_papel = 'titular';
  SELECT COUNT(*) INTO v_post_vice_interino FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND autoridade_papel = 'vice_interino';
  SELECT COUNT(*) INTO v_post_mesa_legislativa FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND autoridade_papel = 'mesa_legislativa';
  SELECT COUNT(*) INTO v_post_outro FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND autoridade_papel = 'outro';
  SELECT COUNT(*) INTO v_post_nao_informado FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND autoridade_papel = 'nao_informado';

  SELECT COUNT(*) INTO v_post_sancionada FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND tipo_relacao = 'lei_sancionada';
  SELECT COUNT(*) INTO v_post_promulgada FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND tipo_relacao = 'lei_promulgada_pelo_legislativo';

  -- Hard validations
  SELECT COUNT(*) INTO v_invalid_aut FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id
    AND autoridade_papel NOT IN ('titular','vice_interino','mesa_legislativa','outro','nao_informado');

  SELECT COUNT(*) INTO v_es_almeida FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id AND signatario = 'ES DE ALMEIDA';

  SELECT COUNT(*) INTO v_promulgada_wrong_aut FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id
    AND tipo_relacao = 'lei_promulgada_pelo_legislativo'
    AND autoridade_papel != 'mesa_legislativa';

  SELECT COUNT(*) INTO v_empty_url FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id
    AND (fonte_primaria_url IS NULL OR fonte_primaria_url = '');

  IF v_post_total <> 2548 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: total esperado=2548 atual=%', v_post_total;
  END IF;
  IF v_post_with_target_id <> 2548 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: rows com coverage_id alvo esperado=2548 atual=%', v_post_with_target_id;
  END IF;
  IF v_post_titular <> 2014 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: titular esperado=2014 atual=%', v_post_titular;
  END IF;
  IF v_post_vice_interino <> 179 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: vice_interino esperado=179 atual=%', v_post_vice_interino;
  END IF;
  IF v_post_mesa_legislativa <> 346 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: mesa_legislativa esperado=346 atual=%', v_post_mesa_legislativa;
  END IF;
  IF v_post_outro <> 9 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: outro esperado=9 atual=%', v_post_outro;
  END IF;
  IF v_post_nao_informado <> 0 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: nao_informado esperado=0 atual=%', v_post_nao_informado;
  END IF;
  IF v_post_sancionada <> 2202 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: lei_sancionada esperado=2202 atual=%', v_post_sancionada;
  END IF;
  IF v_post_promulgada <> 346 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema: lei_promulgada_pelo_legislativo esperado=346 atual=%', v_post_promulgada;
  END IF;

  -- Hard validations
  IF v_invalid_aut <> 0 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema HARD CHECK: autoridade_papel fora do enum esperado=0 atual=%', v_invalid_aut;
  END IF;
  IF v_es_almeida <> 0 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema HARD CHECK: signatario==ES DE ALMEIDA esperado=0 atual=%', v_es_almeida;
  END IF;
  IF v_promulgada_wrong_aut <> 0 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema HARD CHECK: lei_promulgada com autoridade_papel != mesa_legislativa esperado=0 atual=%', v_promulgada_wrong_aut;
  END IF;
  IF v_empty_url <> 0 THEN
    RAISE EXCEPTION 'pos-insercao romeu-zema HARD CHECK: fonte_primaria_url vazia esperado=0 atual=%', v_empty_url;
  END IF;

  RAISE NOTICE 'pos-insercao romeu-zema: total=% titular=% vice_interino=% mesa=% outro=% sancionada=% promulgada=% coverage=%',
    v_post_total, v_post_titular, v_post_vice_interino, v_post_mesa_legislativa, v_post_outro,
    v_post_sancionada, v_post_promulgada, v_post_with_target_id;
END $$;

